import{_ as e,o as l,c as i,e as o}from"./app-0024b173.js";const t={},a=o('<h1 id="食物制作" tabindex="-1"><a class="header-anchor" href="#食物制作" aria-hidden="true">#</a> 食物制作</h1><h2 id="蛋糕胚" tabindex="-1"><a class="header-anchor" href="#蛋糕胚" aria-hidden="true">#</a> 蛋糕胚</h2><p>可按照比例增减原料。</p><ol><li>8 个蛋，黄白分离；蛋黄打散，放入 40g 白糖，80g 油，130g 牛奶，200g 低筋面粉（自己调，对低筋要求不严格），搅匀。</li><li>蛋清用打发器打到泡发：倒扣后蛋清不流动，中途加入 100g 白糖打匀。</li><li>混合。<em>（tip：先取小半蛋清放入蛋黄混合，再将蛋黄全部倒入蛋清。）</em></li></ol><blockquote><p>倒入烘培纸后可随意加入一些白芝麻，葡萄干等。</p></blockquote><ol start="4"><li>烤箱 150℃ 30min.</li></ol><p>此法做出的蛋糕口感一般。经验之谈：</p><ul><li>打发蛋清时尽可能久一点。混合与摆盘快一点。否则不够蓬松。打发时最好往同一方向旋转。</li><li>多加糖更好吃。</li></ul>',8),c=[a];function r(s,n){return l(),i("div",null,c)}const h=e(t,[["render",r],["__file","foods.html.vue"]]);export{h as default};
